"""
    register_oidc_config(company_id, issuer, network_id, scopes)
    register_oidc_config(company_id, issuer, network_id, scopes, params::Dict{String,<:Any})

Registers and saves an OpenID Connect (OIDC) configuration for a Wickr network, enabling
Single Sign-On (SSO) authentication through an identity provider.

# Arguments

- `company_id`: Custom identifier your end users will use to sign in with SSO.
- `issuer`: The issuer URL of the OIDC provider (e.g., 'https://login.example.com').
- `network_id`: The ID of the Wickr network for which OIDC will be configured.
- `scopes`: The OAuth scopes to request from the OIDC provider (e.g., 'openid profile
  email').

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"customUsername"`: A custom field mapping to extract the username from the OIDC token
  (optional).

  !!! note
      The customUsername is only required if you use something other than email as the
      username field.

- `"extraAuthParams"`: Additional authentication parameters to include in the OIDC flow
  (optional).

- `"secret"`: The client secret for authenticating with the OIDC provider (optional).

- `"ssoTokenBufferMinutes"`: The buffer time in minutes before the SSO token expires to
  refresh it (optional).

- `"userId"`: Unique identifier provided by your identity provider to authenticate the
  access request. Also referred to as clientID.
"""
function register_oidc_config end

function register_oidc_config(
    companyId, issuer, networkId, scopes; aws_config::AbstractAWSConfig=current_aws_config()
)
    return wickr(
        "POST",
        "/networks/$(networkId)/oidc/save",
        Dict{String,Any}("companyId" => companyId, "issuer" => issuer, "scopes" => scopes);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function register_oidc_config(
    companyId,
    issuer,
    networkId,
    scopes,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return wickr(
        "POST",
        "/networks/$(networkId)/oidc/save",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "companyId" => companyId, "issuer" => issuer, "scopes" => scopes
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

